+            if result.model.is_some() {
+                return ParsedModelResult {
+                    model: result.model,
+                    thinking_level: if result.warning.is_some() {
+                        None
+                    } else {
+                        Some(thinking_level)
+                    },
+                    warning: result.warning,
+                };
+            }
+        }
+    }
